@using sv_3dc6e6b202494fffab6a447d1463eb64.Services

<div class="catalog-filters">
    <h5>Filters</h5>

    <div class="filter-section">
        <h6>Category</h6>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@IsSelected(category)"
                           @onchange="() => ToggleCategory(category)" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="filter-section">
        <h6>Price Range</h6>
        <div class="mb-2">
            <label class="form-label small">Min Price</label>
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@minPrice" @onchange="e => minPrice = ParseDecimal(e.Value)" min="0" step="0.01" />
        </div>
        <div class="mb-2">
            <label class="form-label small">Max Price</label>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@maxPrice" @onchange="e => maxPrice = ParseDecimal(e.Value)" min="0" step="0.01" />
        </div>
    </div>

    <div class="filter-section">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="in-stock-only"
                   checked="@inStockOnly" @onchange="e => inStockOnly = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="in-stock-only">In Stock Only</label>
        </div>
    </div>

    <div class="filter-actions">
        <button class="btn btn-primary btn-sm w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm w-100" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private bool IsSelected(string category) => selectedCategories.Contains(category);

    private void ToggleCategory(string category)
    {
        if (!selectedCategories.Remove(category))
        {
            selectedCategories.Add(category);
        }
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await ApplyFilters();
    }
}

.catalog-filters {
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
}

.filter-section {
    margin-bottom: 1rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #dee2e6;
}

.filter-section:last-of-type {
    border-bottom: none;
}

.filter-actions {
    margin-top: 1rem;
}

.toolbar-sort-select {
    width: auto;
    min-width: 200px;
}

