arguments.file_text:
@page "/catalog"
@using sv_3dc6e6b202494fffab6a447d1463eb64.Services
@using sv_3dc6e6b202494fffab6a447d1463eb64.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="catalog-layout">
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="@categories" OnFiltersApplied="HandleFiltersApplied" />
    </aside>

    <main class="catalog-main">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <span class="ms-2">Loading products...</span>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="@(result?.TotalCount ?? 0)"
                            Page="@currentPage"
                            PageSize="@pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (result is null || result.Items.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters or search criteria.</p>
                </div>
            }
            else
            {
                <div class="product-grid">
                    @foreach (var product in result.Items)
                    {
                        <ProductCard Product="@product"
                                     OnSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    }
                </div>

                <div class="mt-4">
                    <CatalogPagination Page="@currentPage"
                                       TotalCount="@result.TotalCount"
                                       PageSize="@pageSize"
                                       OnPageChanged="HandlePageChanged" />
                </div>
            }
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.25rem;
}

@@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        max-width: 100%;
    }
}

@page "/catalog"
@using sv_3dc6e6b202494fffab6a447d1463eb64.Services
@using sv_3dc6e6b202494fffab6a447d1463eb64.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="catalog-layout">
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="@categories" OnFiltersApplied="HandleFiltersApplied" />
    </aside>

    <main class="catalog-main">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <span class="ms-2">Loading products...</span>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="@(result?.TotalCount ?? 0)"
                            Page="@currentPage"
                            PageSize="@pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (result is null || result.Items.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters or search criteria.</p>
                </div>
            }
            else
            {
                <div class="product-grid">
                    @foreach (var product in result.Items)
                    {
                        <ProductCard Product="@product"
                                     OnSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    }
                </div>

                <div class="mt-4">
                    <CatalogPagination Page="@currentPage"
                                       TotalCount="@result.TotalCount"
                                       PageSize="@pageSize"
                                       OnPageChanged="HandlePageChanged" />
                </div>
            }
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
