.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.25rem;
}

@@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        max-width: 100%;
    }
}

